import React from 'react';

function Contact() {
  return (
    <div className="p-6">
      <h1 className="text-3xl font-bold text-blue-600 mb-4">Contact Us</h1>
      <p>Email: support@example.com</p>
      <p>Phone: +91-1234567890</p>
    </div>
  );
}

export default Contact;
